class OffsetChange {
  final DateTime atUtc;
  final Duration offsetAfter;

  OffsetChange(this.atUtc, this.offsetAfter) {
    if (!atUtc.isUtc) {
      throw ArgumentError.value(atUtc, 'atUtc', 'must be UTC');
    }
  }
}

class OffsetSchedule {
  final Duration initialOffset;
  final List<OffsetChange> _changes;

  OffsetSchedule(this.initialOffset, Iterable<OffsetChange> changes)
    : _changes = List<OffsetChange>.unmodifiable(
        List<OffsetChange>.of(changes)
          ..sort((a, b) => a.atUtc.compareTo(b.atUtc)),
      );

  Duration offsetAt(DateTime instantUtc) {
    if (!instantUtc.isUtc) {
      throw ArgumentError.value(instantUtc, 'instantUtc', 'must be UTC');
    }

    var result = initialOffset;
    for (final change in _changes) {
      if (!instantUtc.isAfter(change.atUtc)) {
        break;
      }
      result = change.offsetAfter;
    }
    return result;
  }

  DateTime localAt(DateTime instantUtc) {
    return instantUtc.add(offsetAt(instantUtc));
  }
}

