import 'offset_schedule.dart';

class DailyWindowScheduler {
  final OffsetSchedule offsets;

  DailyWindowScheduler(this.offsets);

  DateTime nextRun(DateTime nowUtc, {required int hour, required int minute}) {
    if (!nowUtc.isUtc) {
      throw ArgumentError.value(nowUtc, 'nowUtc', 'must be UTC');
    }
    if (hour < 0 || hour > 23 || minute < 0 || minute > 59) {
      throw ArgumentError('hour and minute must identify a wall-clock minute');
    }

    final localNow = offsets.localAt(nowUtc);
    final localMarker = DateTime.utc(
      localNow.year,
      localNow.month,
      localNow.day,
      localNow.hour,
      localNow.minute,
      localNow.second,
      localNow.millisecond,
      localNow.microsecond,
    );
    var localTarget = DateTime.utc(
      localNow.year,
      localNow.month,
      localNow.day,
      hour,
      minute,
    );
    if (!localTarget.isAfter(localMarker)) {
      localTarget = DateTime.utc(
        localNow.year,
        localNow.month,
        localNow.day + 1,
        hour,
        minute,
      );
    }

    return localTarget.subtract(offsets.offsetAt(nowUtc));
  }
}

