import '../lib/daily_window.dart';
import '../lib/offset_schedule.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final transition = DateTime.utc(2026, 3, 8, 10);
  final changing = OffsetSchedule(const Duration(hours: -8), <OffsetChange>[
    OffsetChange(transition, const Duration(hours: -7)),
  ]);
  check(
    changing.offsetAt(DateTime.utc(2026, 3, 8, 9, 59)) ==
        const Duration(hours: -8),
    'uses the old offset before a change',
  );
  check(
    changing.offsetAt(DateTime.utc(2026, 3, 8, 10, 1)) ==
        const Duration(hours: -7),
    'uses the new offset after a change',
  );

  final fixed = DailyWindowScheduler(
    OffsetSchedule(const Duration(hours: -8), const <OffsetChange>[]),
  );
  check(
    fixed.nextRun(DateTime.utc(2026, 1, 15, 18), hour: 11, minute: 0) ==
        DateTime.utc(2026, 1, 15, 19),
    'schedules later on the same local day',
  );
  check(
    fixed.nextRun(DateTime.utc(2026, 1, 15, 18), hour: 9, minute: 0) ==
        DateTime.utc(2026, 1, 16, 17),
    'rolls an elapsed wall time to the next local day',
  );

  print('public tests passed');
}
